import{_ as i}from"./chunks/moveit.QkHgRnlp.js";import{_ as s,c as a,o as e,a4 as o}from"./chunks/framework.BxjRYGQi.js";const _=JSON.parse('{"title":"使用MoveIt2进行机器人运动规划","description":"","frontmatter":{},"headers":[],"relativePath":"zh/02-quick-start/03-Moveit2_Simulation.md","filePath":"zh/02-quick-start/03-Moveit2_Simulation.md"}'),l={name:"zh/02-quick-start/03-Moveit2_Simulation.md"};function n(r,t,h,p,k,g){return e(),a("div",{"data-pagefind-body":!0},t[0]||(t[0]=[o('<h1 id="使用moveit2进行机器人运动规划" tabindex="-1">使用 MoveIt2 进行机器人运动规划 <a class="header-anchor" href="#使用moveit2进行机器人运动规划" aria-label="Permalink to “使用MoveIt2进行机器人运动规划”">​</a></h1><p>本章节介绍如何使用 MoveIt 2 对捷勃特机器人进行运动规划。MoveIt 2 是基于 ROS 2 平台的机器人运动规划框架，集成了以下核心功能：</p><ul><li><strong>碰撞检测</strong>：在运动规划过程中实时避让环境和自身碰撞</li><li><strong>运动学求解</strong>：提供高效的正、逆运动学解算器</li><li><strong>路径规划</strong>：支持多种平面和空间路径规划算法（如 OMPL、CHOMP、STOMP 等）</li><li><strong>轨迹优化</strong>：对生成的轨迹进行平滑和速度 / 加速度限幅</li><li><strong>轨迹执行</strong>：与硬件控制器无缝对接，实现实时运动控制</li><li><strong>实时重规划</strong>：在动态环境或目标变化时，可自动更新规划结果</li><li><strong>可视化与调试</strong>：通过 RViz 插件展示规划过程，支持交互式目标设置与调参</li></ul><p>借助 MoveIt 2，您可以在仿真或真实机器人上快速生成并执行高质量的臂部运动路径，从而简化开发与调试流程。</p><figure><img src="'+i+'" alt=""></figure><hr><p>要使用 MoveIt2 进行上海捷勃特机器人产品进行路径规划和运动控制，请运行以下命令：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> {机器人型号}_moveit_config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> demo.launch.py</span></span></code></pre></div><p>例如，启动 C5A 型号的 MoveIt2 配置：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> c5a_moveit_config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> demo.launch.py</span></span></code></pre></div><p>这将启动 MoveIt2 的演示界面，允许您进行路径规划和其他操作。</p><blockquote><p>1. 目前仅仅支持 C5A 型号的 MoveIt2 配置，其他型号的 MoveIt2 配置正在开发中。用户也可以根据 MoveIt2 的官方文档自行配置。</p><ol start="2"><li>MoveIt2 配置工具使用说明：<a href="https://moveit.picknik.ai/main/doc/examples/setup_assistant/setup_assistant_tutorial.html#step-1-start" target="_blank" rel="noreferrer">https://moveit.picknik.ai/main/doc/examples/setup_assistant/setup_assistant_tutorial.html#step-1-start</a></li></ol></blockquote>',12)]))}const u=s(l,[["render",n]]);export{_ as __pageData,u as default};
